BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?pkg ?name ?ownerName WHERE {
  ?pkg rdf:type vocab:package .
  ?pkg vocab:NamedElement_name "Alignment and Phasing System" .
  OPTIONAL {
    ?pkg vocab:Element_owner ?owner .
    OPTIONAL { ?owner vocab:NamedElement_name ?ownerName }
  }
}
LIMIT 25

